package com.evernorth.smartemp.controller; import com.evernorth.smartemp.dto.EmployeeDto; import com.evernorth.smartemp.service.EmployeeService; import lombok.RequiredArgsConstructor; import org.springframework.data.domain.*; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/employees") @RequiredArgsConstructor public class EmployeeController{private final EmployeeService s;@GetMapping("/list")public ResponseEntity<List<EmployeeDto.Response>> list(){return ResponseEntity.ok(s.listAll());}@GetMapping public ResponseEntity<Page<EmployeeDto.Response>> search(@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="5")int size,@RequestParam(required=false)String search,@RequestParam(required=false)String department){return ResponseEntity.ok(s.search(search,department,PageRequest.of(page,size)));}}
